async function writeClipboard(text) {
	if (navigator.clipboard && window.isSecureContext) {
		await navigator.clipboard.writeText(text);
		return;
	}

	const input = document.createElement('textarea');
	input.value = text;
	input.setAttribute('readonly', '');
	input.style.position = 'fixed';
	input.style.left = '-9999px';
	document.body.appendChild(input);
	input.select();
	document.execCommand('copy');
	document.body.removeChild(input);
}

function fmtBytes(n) {
	if (n === null || n === undefined || Number.isNaN(Number(n))) return '—';
	if (Number(n) <= 0) return '0 B';
	const units = ['B', 'KB', 'MB', 'GB', 'TB'];
	let i = 0;
	let v = n;

	while (v >= 1024 && i < units.length - 1) {
		v /= 1024;
		i++;
	}

	return `${v.toFixed(v >= 10 || i === 0 ? 0 : 1)} ${units[i]}`;
}

function fmtSeen(ts) {
	if (!ts) return '—';
	const d = new Date(ts);
	if (isNaN(d)) return '—';
	const diff = (Date.now() - d.getTime()) / 1000;
	if (diff < 60) return '刚刚';
	if (diff < 3600) return `${Math.floor(diff / 60)} 分钟前`;
	if (diff < 86400) return `${Math.floor(diff / 3600)} 小时前`;
	return d.toLocaleString();
}

function displayInstallCommand(value) {
	if (!value) return '生成中…';

	return value.replace(/(token=)([^'&\s]+)/, (_, prefix, token) => {
		if (token.length <= 16) return prefix + token;
		return `${prefix}${token.slice(0, 8)}…${token.slice(-4)}`;
	});
}

function instance($$self, $$props, $$invalidate) {
	let nodes = [];
	let loading = true;
	let error = '';
	let installCommand = '';
	let uninstallCommand = '';
	let server = '';
	let hasBinary = true;
	let enrollError = '';
	let copied = '';
	let rotating = false;

	async function fetchNodes() {
		try {
			const res = await fetch('/api/nodes/json');
			if (!res.ok) throw new Error('加载失败');
			const data = await res.json();
			$$invalidate(0, nodes = data.nodes || []);
			$$invalidate(2, error = '');
		} catch(err) {
			$$invalidate(2, error = err.message);
		} finally {
			$$invalidate(1, loading = false);
		}
	}

	// 拉取安装命令（首次会在后端生成准入 token）。
	async function fetchEnroll() {
		try {
			const res = await fetch('/api/nodes/enroll', { method: 'POST' });
			if (!res.ok) throw new Error('获取安装命令失败');
			const data = await res.json();
			$$invalidate(3, installCommand = data.install_command || '');
			$$invalidate(4, uninstallCommand = data.uninstall_command || '');
			$$invalidate(5, server = data.server || '');
			$$invalidate(6, hasBinary = data.has_binary !== false);
			$$invalidate(7, enrollError = '');
		} catch(err) {
			$$invalidate(7, enrollError = err.message);
		}
	}

	let timer;

	onMount(() => {
		fetchNodes();
		fetchEnroll();
		timer = setInterval(fetchNodes, 5000);
	});

	onDestroy(() => clearInterval(timer));

	async function copyCommand(command, kind) {
		if (!command) return;

		try {
			await writeClipboard(command);
			$$invalidate(8, copied = kind);

			setTimeout(
				() => {
					if (copied === kind) $$invalidate(8, copied = '');
				},
				1500
			);
		} catch(err) {
			$$invalidate(7, enrollError = '复制失败：' + err.message);
		}
	}

	function copyInstall() {
		return copyCommand(installCommand, 'install');
	}

	function copyUninstall() {
		return copyCommand(uninstallCommand, 'uninstall');
	}

	// 轮换 token 后，旧命令和已安装 agent 的后续重连都会失效。
	async function rotateToken() {
		if (!confirm('重置后，已有节点重连前需重新安装。继续？')) return;
		$$invalidate(9, rotating = true);

		try {
			const res = await fetch('/api/nodes/token/rotate', { method: 'POST' });
			if (!res.ok) throw new Error('轮换失败');
			await fetchEnroll();
		} catch(err) {
			$$invalidate(7, enrollError = err.message);
		} finally {
			$$invalidate(9, rotating = false);
		}
	}

	async function removeNode(node) {
		if (node.kind === 'local') return;
		if (!confirm(`删除节点「${node.name}」？如果它还在线，重连后会重新登记；应先在该 VPS 上停止 pfagent 服务。`)) return;

		try {
			const res = await fetch('/api/nodes/delete', {
				method: 'POST',
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ node_id: node.node_id })
			});

			if (!res.ok) throw new Error('删除失败');
			await fetchNodes();
		} catch(err) {
			$$invalidate(2, error = err.message);
		}
	}

	const click_handler = node => removeNode(node);

	return [
		nodes,
		loading,
		error,
		installCommand,
		uninstallCommand,
		server,
		hasBinary,
		enrollError,
		copied,
		rotating,
		copyInstall,
		copyUninstall,
		rotateToken,
		removeNode,
		click_handler
	];
}

